import{_ as a,o as t,c as s,ag as i}from"./chunks/framework.BbyMWZAR.js";const g=JSON.parse('{"title":"什么是 JSX？它和 HTML 有什么区别？","description":"","frontmatter":{"title":"什么是 JSX？它和 HTML 有什么区别？","difficulty":"easy","tags":["JSX","React","createElement"],"estimate":10},"headers":[],"relativePath":"domains/react/qa/01-jsx-basics.md","filePath":"domains/react/qa/01-jsx-basics.md","lastUpdated":1783504823000}'),o={name:"domains/react/qa/01-jsx-basics.md"};function r(n,e,c,l,d,h){return t(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="问答题-01-入门-什么是-jsx-它和-html-有什么区别" tabindex="-1">问答题 01（入门）：什么是 JSX？它和 HTML 有什么区别？ <a class="header-anchor" href="#问答题-01-入门-什么是-jsx-它和-html-有什么区别" aria-label="Permalink to &quot;问答题 01（入门）：什么是 JSX？它和 HTML 有什么区别？&quot;">​</a></h1><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p>JSX（JavaScript XML）是 React 提供的一种语法扩展，允许在 JavaScript 中书写类似 HTML 的结构。它并非浏览器可直接识别的语法，而是通过 Babel 等工具编译为 <code>React.createElement(type, props, ...children)</code> 调用，最终生成 React 元素（一个描述 UI 的普通对象）。</p><p>JSX 与 HTML 的主要区别：</p><ol><li><strong>属性命名采用 camelCase</strong>：<code>class</code> → <code>className</code>，<code>for</code> → <code>htmlFor</code>，<code>onclick</code> → <code>onClick</code>。</li><li><strong>JSX 是表达式</strong>：可以赋值给变量、作为参数传递、从函数返回。</li><li><strong>必须有单一根节点</strong>（或使用 <code>&lt;&gt;...&lt;/&gt;</code> Fragment 包裹）。</li><li><strong>使用 <code>{}</code> 插入 JavaScript 表达式</strong>，而非模板字符串或指令。</li><li><strong>标签必须闭合</strong>，包括自闭合标签 <code>&lt;img /&gt;</code>。</li><li><strong>样式使用对象</strong>：<span><code>style={{ color: &#39;red&#39; }}</code></span>，属性名同样 camelCase。</li></ol><div class="language-jsx vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> name</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;React&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> el</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">h1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> className</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;title&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;Hello, {name}!&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">h1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;;</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 编译后 ≈ React.createElement(&quot;h1&quot;, { className: &quot;title&quot; }, &quot;Hello, &quot;, name, &quot;!&quot;)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="追问" tabindex="-1">追问 <a class="header-anchor" href="#追问" aria-label="Permalink to &quot;追问&quot;">​</a></h2><h3 id="追问-1-为什么每个使用-jsx-的文件都要-import-react-在-react-17-之前" tabindex="-1">追问 1：为什么每个使用 JSX 的文件都要 <code>import React</code>（在 React 17 之前）？ <a class="header-anchor" href="#追问-1-为什么每个使用-jsx-的文件都要-import-react-在-react-17-之前" aria-label="Permalink to &quot;追问 1：为什么每个使用 JSX 的文件都要 `import React`（在 React 17 之前）？&quot;">​</a></h3><p><strong>参考答案</strong>：因为 JSX 会被编译成 <code>React.createElement(...)</code>，作用域中必须存在 <code>React</code> 变量。React 17 引入了新的 JSX Transform，编译器会自动从 <code>react/jsx-runtime</code> 引入 <code>jsx</code> 函数，因此不再需要手动 <code>import React</code>（但用到 <code>React.useState</code> 等仍需按需引入）。</p><h3 id="追问-2-fragment-和-div-包裹有什么区别" tabindex="-1">追问 2：<code>&lt;&gt;...&lt;/&gt;</code> Fragment 和 <code>&lt;div&gt;</code> 包裹有什么区别？ <a class="header-anchor" href="#追问-2-fragment-和-div-包裹有什么区别" aria-label="Permalink to &quot;追问 2：`&lt;&gt;...&lt;/&gt;` Fragment 和 `&lt;div&gt;` 包裹有什么区别？&quot;">​</a></h3><p><strong>参考答案</strong>：Fragment 不会在 DOM 中生成额外节点，避免破坏 flex/grid 布局或产生无意义的嵌套。需要传 <code>key</code>（如列表渲染）时须写成完整形式 <code>&lt;React.Fragment key={id}&gt;</code>，简写 <code>&lt;&gt;</code> 不支持属性。</p><h3 id="追问-3-jsx-中的-可以放哪些内容-不能放哪些" tabindex="-1">追问 3：JSX 中的 <code>{}</code> 可以放哪些内容，不能放哪些？ <a class="header-anchor" href="#追问-3-jsx-中的-可以放哪些内容-不能放哪些" aria-label="Permalink to &quot;追问 3：JSX 中的 `{}` 可以放哪些内容，不能放哪些？&quot;">​</a></h3><p><strong>参考答案</strong>：可以放任何 <strong>JavaScript 表达式</strong>（变量、函数调用、三元、数组 map 等）。不能放<strong>语句</strong>（如 <code>if</code>、<code>for</code>、变量声明）。<code>{}</code> 中的 <code>true</code>/<code>false</code>/<code>null</code>/<code>undefined</code> 不会渲染，可用于条件渲染；对象不能直接渲染（除 <code>style</code>）。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/engineer/handbook/domains/react/RESOURCES">React 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://react.dev/learn/writing-markup-with-jsx" target="_blank" rel="noreferrer">React: Writing Markup with JSX</a>：JSX 语法规则、与 HTML 的属性差异及表达式插值</li><li><a href="https://react.dev/learn/your-first-component" target="_blank" rel="noreferrer">React: Your First Component</a>：<code>createElement</code> 与组件返回 UI 的心智模型</li><li><a href="https://react.dev/blog/2020/09/22/introducing-the-new-jsx-transform" target="_blank" rel="noreferrer">Introducing the New JSX Transform</a>：React 17+ 无需手动 <code>import React</code> 的编译变化</li></ul>',16)])])}const k=a(o,[["render",r]]);export{g as __pageData,k as default};
